/**
 * @method
 * @name ascendex#fetchOHLCV
 * @description fetches historical candlestick data containing the open, high, low, and close price, and the volume of a market
 * @param {string} symbol unified symbol of the market to fetch OHLCV data for
 * @param {string} timeframe the length of time each candle represents
 * @param {int} [since] timestamp in ms of the earliest candle to fetch
 * @param {int} [limit] the maximum amount of candles to fetch
 * @param {object} [params] extra parameters specific to the exchange API endpoint
 * @param {int} [params.until] timestamp in ms of the latest candle to fetch
 * @returns {int[][]} A list of candles ordered as timestamp, open, high, low, close, volume
 */
func (this *AscendexCore) FetchOHLCV(symbol any, optionalArgs ...any) <-chan any {
	ch := make(chan any)
	go func() any {
		defer close(ch)
		defer ReturnPanicError(ch)
		timeframe := GetArg(optionalArgs, 0, "1m")
		_ = timeframe
		since := GetArg(optionalArgs, 1, nil)
		_ = since
		limit := GetArg(optionalArgs, 2, nil)
		_ = limit
		params := GetArg(optionalArgs, 3, map[string]any{})
		_ = params

		retRes13018 := (<-this.LoadMarkets())
		PanicOnError(retRes13018)
		var market any = this.Market(symbol)
		var request any = map[string]any{
			"symbol":   GetValue(market, "id"),
			"interval": this.SafeString(this.Timeframes, timeframe, timeframe),
		}
		// if since and limit are not specified
		// the exchange will return just 1 last candle by default
		var duration any = this.ParseTimeframe(timeframe)
		var options any = this.SafeDict(this.Options, "fetchOHLCV", map[string]any{})
		var defaultLimit any = this.SafeInteger(options, "limit", 500)
		var until any = this.SafeInteger(params, "until")
		if IsTrue(!IsEqual(since, nil)) {
			AddElementToObject(request, "from", since)
			if IsTrue(IsEqual(limit, nil)) {
				limit = defaultLimit
			} else {
				limit = mathMin(limit, defaultLimit)
			}
			var toWithLimit any = this.Sum(since, Multiply(Multiply(limit, duration), 1000), 1)
			if IsTrue(!IsEqual(until, nil)) {
				AddElementToObject(request, "to", mathMin(toWithLimit, Add(until, 1)))
			} else {
				AddElementToObject(request, "to", toWithLimit)
			}
		} else if IsTrue(!IsEqual(until, nil)) {
			AddElementToObject(request, "to", Add(until, 1))
			if IsTrue(IsEqual(limit, nil)) {
				limit = defaultLimit
			} else {
				limit = mathMin(limit, defaultLimit)
			}
			AddElementToObject(request, "from", Subtract(until, (Multiply(Multiply(limit, duration), 1000))))
		} else if IsTrue(!IsEqual(limit, nil)) {
			AddElementToObject(request, "n", limit) // max 500
		}
		params = this.Omit(params, "until")

		response := (<-this.V1PublicGetBarhist(this.Extend(request, params)))
		PanicOnError(response)
		//
		//     {
		//         "code":0,
		//         "data":[
		//             {
		//                 "m":"bar",
		//                 "s":"BTC/USDT",
		//                 "data":{
		//                     "i":"1",
		//                     "ts":1590228000000,
		//                     "o":"9139.59",
		//                     "c":"9131.94",
		//                     "h":"9139.99",
		//                     "l":"9121.71",
		//                     "v":"25.20648"
		//                 }
		//             }
		//         ]
		//     }
		//
		var data any = this.SafeList(response, "data", []any{})

		ch <- this.ParseOHLCVs(data, market, timeframe, since, limit)
		return nil

	}()
	return ch
}
func (this *AscendexCore) ParseTrade(trade any, optionalArgs ...any) any {
	//
	// public fetchTrades
	//
	//     {
	//         "p":"9128.5", // price
	//         "q":"0.0030", // quantity
	//         "ts":1590229002385, // timestamp
	//         "bm":false, // if true, the buyer is the market maker, we only use this field to "define the side" of a public trade
	//         "seqnum":180143985289898554
	//     }
	//
	market := GetArg(optionalArgs, 0, nil)
	_ = market
	var timestamp any = this.SafeInteger(trade, "ts")
	var priceString any = this.SafeString2(trade, "price", "p")
	var amountString any = this.SafeString(trade, "q")
	var buyerIsMaker any = this.SafeBool(trade, "bm", false)
	var side any = Ternary(IsTrue(buyerIsMaker), "sell", "buy")
	market = this.SafeMarket(nil, market)
	return this.SafeTrade(map[string]any{
		"info":         trade,
		"timestamp":    timestamp,
		"datetime":     this.Iso8601(timestamp),
		"symbol":       GetValue(market, "symbol"),
		"id":           nil,
		"order":        nil,
		"type":         nil,
		"takerOrMaker": nil,
		"side":         side,
		"price":        priceString,
		"amount":       amountString,
		"cost":         nil,
		"fee":          nil,
	}, market)
}

