		//                  "posTakeProfitTrigger":"market",
		//                  "liquidityInd":"n"
		//              }
		//          }
		//      }
		//
		var data any = this.SafeDict(response, "data", map[string]any{})
		var order any = this.SafeDict2(data, "order", "info", map[string]any{})

		ch <- this.ParseOrder(order, market)
